import{_ as p,C as t,o as s,c as d,j as e,a as i,E as n,a3 as u}from"./chunks/framework.CVjg771q.js";const k=JSON.parse('{"title":"庄子·逍遥游","description":"围绕逍遥游、大鹏小知之辨展开庄子的自由视野。","frontmatter":{"title":"庄子·逍遥游","description":"围绕逍遥游、大鹏小知之辨展开庄子的自由视野。","category":"guide","aliases":["逍遥游","庄子逍遥游","zhuangzi chapter 01"],"source":["《庄子》","维基文库：庄子·逍遥游"]},"headers":[],"relativePath":"daoism/texts/zhuang-zi/chapter-01.md","filePath":"daoism/texts/zhuang-zi/chapter-01.md","lastUpdated":1778126077000}'),m={name:"daoism/texts/zhuang-zi/chapter-01.md"};function c(x,a,b,g,_,f){const r=t("DaoReadingPrelude"),l=t("DaoOriginalReadingGroup"),o=t("DaoLineGuide"),h=t("DaoKeywordCards");return s(),d("div",null,[a[0]||(a[0]=e("h1",{id:"庄子·逍遥游",tabindex:"-1"},[i("庄子·逍遥游 "),e("a",{class:"header-anchor",href:"#庄子·逍遥游","aria-label":'Permalink to "庄子·逍遥游"'},"​")],-1)),n(r,{title:"从大鹏与小知，进入庄子的自由世界",summary:"逍遥游是《庄子》内篇第一篇，也是最常被引用的篇章之一。这一轮先把原文顺下来，看清楚大鹏、蜩鸠、宋荣子、列子、许由、接舆、惠子等人物的出场顺序，以及庄子如何用一个接一个的故事来推「大小之辨」和「无用之用」。",points:[{label:"先看",text:"顺着原文走，看清大鹏→蜩鸠→宋荣子→列子→许由→接舆→惠子的人物链条。"},{label:"再问",text:"庄子为什么从「大小之辨」一直推到「无用之大用」？"},{label:"最后",text:"想一想：今天读到「逍遥」两个字，感受到的是逃避，还是一种更大的自由？"}],hint:"如果你是第一次读庄子，这一篇最需要的是顺着故事走一遍，不需要急着总结。"}),a[1]||(a[1]=e("h2",{id:"【原典层】原文",tabindex:"-1"},[i("【原典层】原文 "),e("a",{class:"header-anchor",href:"#【原典层】原文","aria-label":'Permalink to "【原典层】原文"'},"​")],-1)),n(l,{paragraphs:["北冥有鱼，其名为鲲。鲲之大，不知其几千里也。化而为鸟，其名为鹏。鹏之背，不知其几千里也；怒而飞，其翼若垂天之云。是鸟也，海运则将徙于南冥。南冥者，天池也。","齐谐者，志怪者也。谐之言曰：「鹏之徙于南冥也，水击三千里，抟扶摇而上者九万里，去以六月息者也。」野马也，尘埃也，生物之以息相吹也。天之苍苍，其正色邪？其远而无所至极邪？其视下也亦若是，则已矣。","且夫水之积也不厚，则负大舟也无力。覆杯水于坳堂之上，则芥为之舟，置杯焉则胶，水浅而舟大也。风之积也不厚，则其负大翼也无力。故九万里则风斯在下矣，而后乃今培风；背负青天而莫之夭阏者，而后乃今将图南。","蜩与学鸠笑之曰：「我决起而飞，枪榆、枋，时则不至而控于地而已矣，奚以之九万里而南为？」适莽苍者三餐而反，腹犹果然；适百里者宿舂粮；适千里者三月聚粮。之二虫又何知！","小知不及大知，小年不及大年。奚以知其然也？朝菌不知晦朔，蟪蛄不知春秋，此小年也。楚之南有冥灵者，以五百岁为春，五百岁为秋；上古有大椿者，以八千岁为春，八千岁为秋。而彭祖乃今以久特闻，众人匹之，不亦悲乎！","汤之问棘也是已。穷发之北，有冥海者，天池也。有鱼焉，其广数千里，未有知其修者，其名为鲲。有鸟焉，其名为鹏，背若泰山，翼若垂天之云，抟扶摇羊角而上者九万里，绝云气，负青天，然后图南，且适南冥也。斥鴳笑之曰：「彼且奚适也？我腾跃而上，不过数仞而下，翱翔蓬蒿之间，此亦飞之至也。而彼且奚适也？」此小大之辩也。","故夫知效一官，行比一乡，德合一君而征一国者，其自视也亦若此矣。而宋荣子犹然笑之。且举世而誉之而不加劝，举世而非之而不加沮，定乎内外之分，辩乎荣辱之境，斯已矣。彼其于世，未数数然也。虽然，犹有未树也。夫列子御风而行，泠然善也，旬有五日而后反。彼于致福者，未数数然也。此虽免乎行，犹有所待者也。若夫乘天地之正，而御六气之辩，以游无穷者，彼且恶乎待哉！故曰：至人无己，神人无功，圣人无名。","尧让天下于许由，曰：「日月出矣，而爝火不息，其于光也，不亦难乎！时雨降矣，而犹浸灌，其于泽也，不亦劳乎！夫子立而天下治，而我犹尸之，吾自视缺然，请致天下。」许由曰：「子治天下，天下既已治也。而我犹代子，吾将为名乎？名者，实之宾也，吾将为宾乎？鹪鹩巢于深林，不过一枝；偃鼠饮河，不过满腹。归休乎君！予无所用天下为。庖人虽不治庖，尸祝不越樽俎而代之矣。」","肩吾问于连叔曰：「吾闻言于接舆，大而无当，往而不反。吾惊怖其言，犹河汉而无极也，大有径庭，不近人情焉。」连叔曰：「其言谓何哉？」曰：「藐姑射之山，有神人居焉，肌肤若冰雪，淖约若处子，不食五谷，吸风饮露。乘云气，御飞龙，而游乎四海之外。其神凝，使物不疵疠而年谷熟。吾以是狂而不信也。」连叔曰：「然，瞽者无以与乎文章之观，聋者无以与乎钟鼓之声。岂唯形骸有聋盲哉？夫知亦有之。是其言也，犹时女也。之人也，之德也，将旁礴万物，以为一世蕲乎乱，孰弊弊焉以天下为事！之人也，物莫之伤，大浸稽天而不溺，大旱、金石流、土山焦而不热。是其尘垢秕糠，将犹陶铸尧、舜者也，孰肯以物为事！宋人资章甫而适诸越，越人断发文身，无所用之。尧治天下之民，平海内之政，往见四子藐姑射之山，汾水之阳，窅然丧其天下焉。」","惠子谓庄子曰：「魏王贻我大瓠之种，我树之成而实五石，以盛水浆，其坚不能自举也。剖之以为瓢，则瓠落无所容。非不呺然大也，吾为其无用而掊之。」庄子曰：「夫子固拙于用大矣。宋人有善为不龟手之药者，世世以洴澼絖为事。客闻之，请买其方百金。聚族而谋曰：『我世世为洴澼絖，不过数金；今一朝而鬻技百金，请与之。』客得之，以说吴王。越有难，吴王使之将。冬，与越人水战，大败越人，裂地而封之。能不龟手一也，或以封，或不免于洴澼絖，则所用之异也。今子有五石之瓠，何不虑以为大樽而浮乎江湖，而忧其瓠落无所容？则夫子犹有蓬之心也夫！」","惠子谓庄子曰：「吾有大树，人谓之樗。其大本拥肿而不中绳墨，其小枝卷曲而不中规矩，立之涂，匠者不顾。今子之言，大而无用，众所同去也。」庄子曰：「子独不见狸狌乎？卑身而伏，以候敖者；东西跳梁，不辟高下；中于机辟，死于罔罟。今夫斄牛，其大若垂天之云。此能为大矣，而不能执鼠。今子有大树，患其无用，何不树之于无何有之乡，广莫之野，彷徨乎无为其侧，逍遥乎寝卧其下？不夭斤斧，物无害者，无所可用，安所困苦哉！」"]}),n(o,{lines:[{label:"起",text:"大鹏图南，势极而不矜；蜩鸠笑之，居小而不自知——起笔即设大小之辨。"},{label:"承",text:"水积不厚则负舟无力，风积不厚则负翼无力——以物理喻视野。"},{label:"转一",text:"朝菌不知晦朔，蟪蛄不知春秋——小年不及大年，将大小之辨推向时间维度。"},{label:"转二",text:"宋荣子笑之，列子御风——逐步推出四种不同层次的「自由」。"},{label:"转三",text:"至人无己，神人无功，圣人无名——将篇章推向庄子哲学的核心命题。"},{label:"证一",text:"尧让天下于许由：以「名者实之宾」诠释「圣人无名」。"},{label:"证二",text:"接舆藐姑射山之神人：以「孰弊弊焉以天下为事」诠释「神人无功」。"},{label:"证三",text:"大瓠与不龟手之药：以「所用之异」诠释「无用之大用」。"},{label:"收束",text:"大树樗，树之于无何有之乡——逍遥不是逃离，而是在无用中得大用。"}]}),a[2]||(a[2]=e("h2",{id:"【原典层】字词释义",tabindex:"-1"},[i("【原典层】字词释义 "),e("a",{class:"header-anchor",href:"#【原典层】字词释义","aria-label":'Permalink to "【原典层】字词释义"'},"​")],-1)),n(h,{items:[{term:"鲲",pinyin:["kūn"],explanation:"传说中的大鱼，后化为大鹏。以极端之「大」开启庄子视野。"},{term:"鹏",pinyin:["péng"],explanation:"由鲲所化的大鸟，翼若垂天之云，象征极大视野与极高飞翔。"},{term:"冥",pinyin:["míng"],explanation:"深远幽暗。北冥、南冥均为庄子想象中的极远之海。"},{term:"抟",pinyin:["tuán"],explanation:"盘旋而上。抟扶摇，描写大鹏乘风旋转而上的姿态。"},{term:"夭阏",pinyin:["yāo","è"],explanation:"阻挡、挫折。莫之夭阏，指没有障碍可以阻挡。"},{term:"朝菌",pinyin:["zhāo","jùn"],explanation:"朝生暮死的菌类，比喻生命极短暂的事物。"},{term:"蟪蛄",pinyin:["huì","gū"],explanation:"寒蝉，春生夏死或夏生秋死，不知一年之始终。"},{term:"姑射",pinyin:["gū","yè"],explanation:"传说中的仙山名，形容远离尘世的超越境界。"},{term:"淖约",pinyin:["chuò","yuē"],explanation:"形容姿态柔美、绰约。庄子以处女之美喻神人之态。"},{term:"瓠",pinyin:["hù"],explanation:"葫芦。大瓠之喻是庄子讨论「有用/无用」的核心寓言。"},{term:"洴澼絖",pinyin:["píng","pì","kuàng"],explanation:"漂洗丝絮。宋人世世代代以此为业，是庄子笔下「小用」的代表。"},{term:"樗",pinyin:["chū"],explanation:"臭椿树，因材质不佳被视为无用。庄子以樗树反说「无用之大用」。"},{term:"罔罟",pinyin:["wǎng","gǔ"],explanation:"网罗、陷阱。比喻人为机巧反伤自身的处境。"},{term:"斄牛",pinyin:["lí","niú"],explanation:"牦牛，体大如垂天之云却不能捕鼠，比喻大才不用于小处。"}]}),a[3]||(a[3]=u("",15))])}const P=p(m,[["render",c]]);export{k as __pageData,P as default};
